import React, { useState } from 'react';
import { BookText, BookOpenCheck, Layers, Lightbulb, FileText } from 'lucide-react';

const tabs = [
  { name: 'Getting Started', icon: <BookOpenCheck className="w-5 h-5 mr-1" /> },
  { name: 'Project Types', icon: <Layers className="w-5 h-5 mr-1" /> },
  { name: 'Best Practices', icon: <Lightbulb className="w-5 h-5 mr-1" /> },
  { name: 'Examples', icon: <FileText className="w-5 h-5 mr-1" /> },
];

const tabContent = {
  'Getting Started': (
    <div className="bg-[#23232a] rounded-xl p-6 text-white border border-purple-800 animate-pop-fade">
      <h3 className="text-xl font-bold mb-2 text-fuchsia-400 flex items-center gap-2"><BookOpenCheck className="w-6 h-6" /> Welcome to CodeGen AI</h3>
      <p className="text-gray-300 mb-2">Generate complete, production-ready projects with AI-powered code generation.</p>
      <ul className="text-gray-400 text-sm list-disc pl-5">
        <li>Complete Project Generation: Get full project structures, not just snippets</li>
        <li>Multiple Project Types: React, Next.js, Vue.js, Vanilla JS</li>
        <li>Production Ready: Generated code follows best practices and industry standards</li>
        <li>Download & Execute: Download and run projects immediately</li>
        <li>Modern Technologies: TypeScript, Tailwind CSS, and more</li>
      </ul>
    </div>
  ),
  'Project Types': (
    <div className="bg-[#23232a] rounded-xl p-6 text-white border border-purple-800 animate-pop-fade">
      <h3 className="text-xl font-bold mb-2 text-blue-400 flex items-center gap-2"><Layers className="w-6 h-6" /> Project Types</h3>
      <ul className="text-gray-300 text-sm list-disc pl-5">
        <li>React App</li>
        <li>Next.js App</li>
        <li>Vue.js App</li>
        <li>Vanilla JavaScript</li>
      </ul>
    </div>
  ),
  'Best Practices': (
    <div className="bg-[#23232a] rounded-xl p-6 text-white border border-purple-800 animate-pop-fade">
      <h3 className="text-xl font-bold mb-2 text-yellow-400 flex items-center gap-2"><Lightbulb className="w-6 h-6" /> Best Practices</h3>
      <ul className="text-gray-300 text-sm list-disc pl-5">
        <li>Write clear and concise project descriptions</li>
        <li>Choose the right project type for your needs</li>
        <li>Review and test generated code before deploying</li>
        <li>Use version control for your projects</li>
      </ul>
    </div>
  ),
  'Examples': (
    <div className="bg-[#23232a] rounded-xl p-6 text-white border border-purple-800 animate-pop-fade">
      <h3 className="text-xl font-bold mb-2 text-green-400 flex items-center gap-2"><FileText className="w-6 h-6" /> Examples</h3>
      <ul className="text-gray-300 text-sm list-disc pl-5">
        <li>Todo App: A simple todo list with React and TypeScript</li>
        <li>Portfolio Site: Personal portfolio with Next.js</li>
        <li>Blog Platform: Multi-user blog with Vue.js</li>
        <li>Landing Page: Responsive landing page with Vanilla JS</li>
      </ul>
    </div>
  ),
};

function Docs() {
  const [activeTab, setActiveTab] = useState('Getting Started');
  return (
    <div className="min-h-screen bg-gradient-to-br from-[#18181b] via-[#23232a] to-[#1e1b4b] flex flex-col items-center py-12 px-2 animate-fade-in-up">
      <h1 className="text-4xl font-extrabold text-center mb-10 bg-gradient-to-r from-fuchsia-400 to-blue-500 bg-clip-text text-transparent flex items-center justify-center gap-2">
        <BookText className="w-8 h-8 text-fuchsia-400 animate-pulse" /> Documentation
      </h1>
      <div className="w-full max-w-4xl">
        <div className="flex justify-center gap-2 mb-6">
          {tabs.map(tab => (
            <button
              key={tab.name}
              className={`relative flex items-center px-4 py-2 rounded-t-lg font-semibold text-base transition-all duration-200 border-b-2
                ${activeTab === tab.name ? 'text-white border-fuchsia-400' : 'text-gray-300 border-transparent hover:text-white'}
              `}
              onClick={() => setActiveTab(tab.name)}
            >
              {tab.icon}
              {tab.name}
              <span
                className={`absolute left-2 right-2 -bottom-1 h-0.5 rounded transition-all duration-200
                  ${activeTab === tab.name ? 'bg-gradient-to-r from-fuchsia-500 to-blue-500 w-[90%] opacity-100' : 'bg-gradient-to-r from-fuchsia-500 to-blue-500 w-0 opacity-0 group-hover:w-[90%] group-hover:opacity-100'}`}
              />
            </button>
          ))}
        </div>
        <div className="animate-pop-fade">
          {tabContent[activeTab]}
        </div>
      </div>
      {/* Animations */}
      <style>{`
        .animate-fade-in-up {
          animation: fadeInUp 1s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        .animate-pop-fade {
          animation: popFadeIn 1s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        @keyframes fadeInUp {
          from { opacity: 0; transform: translateY(40px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes popFadeIn {
          0% { opacity: 0; transform: translateY(40px) scale(0.95); }
          60% { opacity: 1; transform: translateY(-8px) scale(1.05); }
          100% { opacity: 1; transform: translateY(0) scale(1); }
        }
      `}</style>
    </div>
  );
}

export default Docs;
